import os
from pathlib import Path

repo_root = Path(r'C:\Users\Hp\Documents\Shopify Scraping Script')
memory_root = repo_root / '.memory'

def check_file(file_path):
    try:
        with open(file_path, 'rb') as f:
            content = f.read()
            if len(content) > 10250 and content[10250] == 0x97:
                return True, len(content)
    except Exception as e:
        return None, str(e)
    return False, len(content) if 'content' in locals() else 0

print('Checking all memory files for byte 0x97 at position 10250...\n')

for root, dirs, files in os.walk(memory_root):
    for file in files:
        if file.endswith(('.json', '.jsonl', '.md')):
            file_path = Path(root) / file
            result, size = check_file(file_path)
            if result is True:
                print(f'FOUND: {file_path}')
                print(f'  Size: {size} bytes')
                print(f'  Byte at 10250: 0x97')
                # Show surrounding context
                with open(file_path, 'rb') as f:
                    f.seek(max(0, 10250 - 50))
                    context = f.read(100)
                    print(f'  Context (bytes): {context[:50]}...{context[50:]}')
            elif result is None:
                print(f'ERROR reading {file_path}: {size}')
