import os
files = []
for root, dirs, filenames in os.walk('.memory'):
    for f in filenames:
        if f.endswith(('.json', '.jsonl', '.md')):
            path = os.path.join(root, f)
            try:
                with open(path, 'r', encoding='utf-8') as fp:
                    fp.read()
            except UnicodeDecodeError as e:
                files.append((path, str(e)))
for path, error in files:
    print(f'{path}: {error}')
